  ?edition wdt:P1545 wd:Q1363275 .
  ?edition wdt:P373 ?game .
  { 
    ?game wdt:P136 wd:Q334634 .
    ?game wdt:P1478 wd:Q650840 .
    ?game wdt:P3325 ?attendance .
  }
  UNION
  {
    ?game wdt:P136 wd:Q650840 .
    ?game wdt:P1478 wd:Q334634 .
    ?game wdt:P3325 ?attendance .
  }
} ORDER BY DESC(?attendance) LIMIT 1

